private static Type resolve(Type context, Class<?> contextRawType, Type toResolve,
                            Collection<TypeVariable> visitedTypeVariables) {
  // Track visited type variables to avoid infinite recursion
  if (visitedTypeVariables.contains(toResolve)) {
    return toResolve; // Return the same type if it's already visited
  }
  visitedTypeVariables.add((TypeVariable<?>) toResolve); // Add the current type variable to the set

